module RefModule (CLK, RST, Q);
input CLK, RST;
output reg [3:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST) begin
        Q <= 4'b0000;
    end else begin
        Q <= {~Q[0], Q[3:1]};
    end
end

endmodule
